def extract_credit_report_fields(text: str) -> Dict[str, Any]:
    """Extract bureau FICO scores from merged tri-merge credit report PDFs."""
    facts: Dict[str, Any] = {}
    bureau_scores: Dict[str, int] = {}

    patterns: Tuple[Tuple[str, str], ...] = (
        ("transunion", r"FICO Risk Score, Classic \(04\)\s*(\d{3})"),
        ("experian", r"Fair Isaac \(v2\)\s*\[\s*(\d{3})\s*\]"),
        ("equifax", r"FICO Classic v5\s+(\d{3})"),
    )
    for bureau, pat in patterns:
        m = re.search(pat, text, re.IGNORECASE)
        if m:
            score = int(m.group(1))
            if 300 <= score < 850:
                bureau_scores[bureau] = score

    if not bureau_scores:
        for m in re.finditer(r"(\d{3})\s+Factors\s*•", text):
            score = int(m.group(1))
            if 300 <= score <= 850:
                bureau_scores.setdefault(f"bureau_{len(bureau_scores) + 1}", score)

    if bureau_scores:
        facts["bureau_fico_scores"] = bureau_scores
        scores = sorted(bureau_scores.values())
        mid = scores[len(scores) // 2]
        facts["primary_fico_score"] = mid
        facts["credit_score_mention"] = mid
    return facts


